let imageSuggestions = $input.first().json.message?.content;

if (typeof imageSuggestions === 'string') {
  imageSuggestions = imageSuggestions.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  try {
    imageSuggestions = JSON.parse(imageSuggestions);
  } catch (e) {
    imageSuggestions = { images: [] };
  }
}

const images = imageSuggestions.images || [];

return images.map((img, index) => ({
  json: {
    ...img,
    imageIndex: index,
    totalImages: images.length
  }
}));

// Get the binary data from the downloaded image
const binaryData = $input.first().binary.data;
const itemData = $('Loop Over Items').first().json;

// Convert binary to base64
const base64Data = binaryData.data;

// Generate filename
const timestamp = Date.now();
const filename = `blog-image-${timestamp}-${itemData.imageIndex}.png`;

return [{
  json: {
    filename: filename,
    mimeType: 'image/png',
    data: base64Data,
    altText: itemData.altText,
    caption: itemData.caption,
    insertAfterBlock: itemData.insertAfterBlock,
    purpose: itemData.purpose
  }
}];

// Prepare data for media library registration
const uploadResponse = $input.first().json;
const prepareData = $('Prepare Upload Data').first().json;

if (!uploadResponse.success || !uploadResponse.data) {
  throw new Error('Upload failed: ' + JSON.stringify(uploadResponse));
}

const uploadData = uploadResponse.data;

return [{
  json: {
    url: uploadData.url,
    storedFilename: uploadData.storedFilename,
    mimeType: uploadData.mimeType,
    fileSize: uploadData.fileSize,
    altText: prepareData.altText,
    caption: prepareData.caption,
    insertAfterBlock: prepareData.insertAfterBlock,
    purpose: prepareData.purpose
  }
}];

// Collect all generated images with their metadata
const allItems = $input.all();

const images = allItems.map(item => ({
  insertAfterBlock: item.json.insertAfterBlock || 0,
  url: item.json.url || '',
  altText: item.json.altText || '',
  caption: item.json.caption || '',
  purpose: item.json.purpose || ''
}));

return [{
  json: {
    images: images,
    imageCount: images.length,
    processedAt: new Date().toISOString()
  }
}];

