const enhancedContent = $input.first().json.message?.content;
const originalArticle = $('Write Article').first().json.message?.content;
const topicData = $('Parse Research').first().json;

let blocks = enhancedContent?.blocks || originalArticle?.blocks || [];
let excerpt = originalArticle?.excerpt || '';
let title = topicData.topic;

const slug = title
  .toLowerCase()
  .replace(/[^a-z0-9\s-]/g, '')
  .replace(/\s+/g, '-')
  .replace(/-+/g, '-')
  .substring(0, 100);

const content = {
  blocks: blocks,
  version: "1.0"
};

return [{
  json: {
    title: title,
    slug: slug,
    postType: 'blog',
    excerpt: excerpt,
    content: JSON.stringify(content),
    coverImage: '',
    published: false,
    publishedAt: null,
    categoryIds: topicData.targetCategoryId ? [topicData.targetCategoryId] : [],
    tagIds: topicData.targetTagIds || [],
    customFields: {
      generatedAt: new Date().toISOString(),
      researchSources: JSON.stringify(topicData.citations || []),
      aiEnhanced: true,
      imageCount: blocks.filter(b => b.type === 'columns').length
    },
    _metadata: {
      topic: topicData.topic,
      angle: topicData.angle,
      targetAudience: topicData.targetAudience
    }
  }
}];

const postResponse = $input.first().json;
const formatData = $('Format for API').first().json;

const postId = postResponse.id || postResponse.post?.id || 'unknown';
const postSlug = postResponse.slug || formatData.slug;

const baseUrl = 'http://localhost:3000';
const reviewUrl = `${baseUrl}/admin/posts/${postId}/edit`;
const previewUrl = `${baseUrl}/blog/${postSlug}`;

return [{
  json: {
    postId: postId,
    title: formatData.title,
    slug: postSlug,
    excerpt: formatData.excerpt,
    reviewUrl: reviewUrl,
    previewUrl: previewUrl,
    metadata: formatData._metadata,
    imageCount: formatData.customFields.imageCount,
    createdAt: new Date().toISOString()
  }
}];
